  animation: palette-appear $transition-slow ease-out both;
}

.command-palette__body {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.command-palette__list-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  overflow: hidden;

  .command-palette__body--has-detail & {
    flex: 0 0 40%;
  }
}

@use '../../styles/tokens' as *;

.search-bar {
  display: flex;
  align-items: center;
  height: $search-bar-height;
  padding: 0 $space-4;
  border-bottom: 1px solid $color-border;
  gap: $space-3;
}

.search-bar__icon {
  flex-shrink: 0;
  color: $color-text-tertiary;
}

.search-bar__breadcrumbs {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: $space-half;
}

.search-bar__breadcrumb {
  display: inline-flex;
  align-items: center;
  padding: $space-half $space-2;
  border: none;
  border-radius: $radius-sm;
  background: $color-surface-hover;
  font-family: $font-family;
  font-size: $font-sm;
  color: $color-text-secondary;
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-border;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -1px;
  }

  &--current {
    cursor: default;

    &:hover {
      background: $color-surface-hover;
    }
  }
}

.search-bar__breadcrumb-chevron {
  flex-shrink: 0;
  color: $color-text-tertiary;
}

.search-bar__input {
  flex: 1;
  min-width: 0;
  height: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-family: $font-family;
  font-size: $font-lg;
  color: $color-text-primary;
  caret-color: $color-accent;

  &::placeholder {
    color: $color-text-tertiary;
  }
}

@use '../../styles/tokens' as *;

.action-panel {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $action-panel-height;
  padding: 0 $space-2;
  border-top: 1px solid $color-border;
  background-color: $color-surface-footer;
  border-radius: 0 0 $radius-lg $radius-lg;
  flex-shrink: 0;
  animation: action-panel-slide-up $transition-slow ease-out both;
  animation-delay: $transition-fast;

  &__primary,
  &__secondary {
    display: flex;
    align-items: center;
    gap: $space-3;
  }

  &__action {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    color: $color-text-secondary;
    font-family: $font-family;
    font-size: $font-sm;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
      color: $color-text-primary;
    }

    &:focus-visible {
      outline: 2px solid $color-accent;
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__label {
    white-space: nowrap;
  }

  &__shortcut {
    display: inline-flex;
    align-items: center;
    gap: $space-half;
  }
}

